【问题】Go 允许多个返回值吗？

【答案】
允许 
func swap(x, y string) (string, string) { 
 return y, x 
} 

func main() { 
 a, b := swap( "A", "B") 
 fmt.Println(a, b) // B A 
}

【标签】
Golang

允许 
func swap(x, y string) (string, string) { 
 return y, x 
} 

func main() { 
 a, b := swap( "A", "B") 
 fmt.Println(a, b) // B A 
}

