通常采用的方式如下，遍历比较切片中的每一个元素（注意处理越界的情况）。 
func StringSliceEqualBCE(a, b [] string) bool { 
 if len(a) != len(b) { 
 return false 
 } 

 if (a == nil) != (b == nil) { 
 return false 
 } 

 b = b[:len(a)] 
 for i, v := range a { 
 if v != b[i] { 
 return false 
 } 

 } 

 return true 
}

